import type { ExamQuestion } from "./types";

export const npExamBatch74Questions: ExamQuestion[] = [
  { q: "A patient with heart failure presents with EF of 30%. Current medications include lisinopril and carvedilol. Which additional medication has demonstrated mortality reduction and should be added?", o: ["Amlodipine", "Sacubitril/valsartan (replacing lisinopril), spironolactone, and SGLT2 inhibitor (dapagliflozin or empagliflozin) — all have Class I recommendations for HFrEF", "Digoxin", "Hydralazine"], a: 1, r: "HFrEF GDMT (guideline-directed medical therapy) includes four pillars, each with proven mortality reduction: 1) ARNI (sacubitril/valsartan) replacing ACEi/ARB (PARADIGM-HF trial), 2) Beta-blocker (carvedilol, metoprolol succinate, bisoprolol), 3) MRA (spironolactone or eplerenone, RALES/EMPHASIS-HF), 4) SGLT2 inhibitor (dapagliflozin DAPA-HF or empagliflozin EMPEROR-Reduced). Initiate and uptitrate simultaneously when possible. Additional: hydralazine/isosorbide dinitrate for Black patients (A-HeFT). ICD if EF <=35% despite 3 months GDMT.", s: "Cardiovascular" },
  { q: "A 45-year-old presents with a thyroid nodule. Ultrasound shows a 2.5 cm hypoechoic nodule with microcalcifications and irregular margins. TSH is normal. What is the next step?", o: ["Repeat ultrasound in 6 months", "Fine-needle aspiration biopsy; hypoechoic nodule with microcalcifications and irregular margins has high suspicion features per ACR TI-RADS warranting FNA at >=1 cm", "Thyroid lobectomy", "Radioiodine scan"], a: 1, r: "Thyroid nodule evaluation: TSH first. If low TSH: radionuclide scan (hot nodule = unlikely malignant). If normal/elevated TSH: ultrasound characterization using ACR TI-RADS. High-suspicion features: hypoechoic, microcalcifications, taller-than-wide, irregular margins, extrathyroidal extension. TI-RADS 5 (high suspicion): FNA if >=1 cm. TI-RADS 4: FNA if >=1.5 cm. TI-RADS 3: FNA if >=2.5 cm. Bethesda cytology system guides management: I (non-diagnostic, repeat), II (benign, surveillance), III-IV (indeterminate, molecular testing or lobectomy), V-VI (suspicious/malignant, surgery).", s: "Endocrine & Metabolic" },
  { q: "A 70-year-old with history of stroke and atrial fibrillation is on apixaban. The patient needs an elective knee replacement. How should anticoagulation be managed perioperatively?", o: ["Continue apixaban through surgery", "Hold apixaban 48-72 hours before surgery (based on renal function); no bridging needed for most DOACs; resume 48-72 hours postoperatively when hemostasis is achieved", "Switch to warfarin before surgery", "Bridge with enoxaparin"], a: 1, r: "DOAC perioperative management (PAUSE trial): DOACs have predictable pharmacokinetics, so bridging is NOT needed. APIXABAN/RIVAROXABAN: hold 48 hours before high-bleeding-risk surgery (72 hours if CrCl <50). DABIGATRAN: hold 48-72 hours (longer if CrCl <50 due to renal clearance). Resumption: 48-72 hours postoperatively when adequate hemostasis. BRIDGING with heparin increases bleeding risk without reducing thrombotic events (BRIDGE trial for warfarin, PAUSE for DOACs). Exception: mechanical heart valves on warfarin may need bridging.", s: "Hematology" },
  { q: "A 28-year-old presents with a pruritic, annular, raised, scaly lesion on the arm with central clearing. What is the diagnosis and treatment?", o: ["Eczema", "Tinea corporis (dermatophyte ringworm); treat with topical antifungal (terbinafine or clotrimazole) for 2-4 weeks; confirm with KOH prep showing branching hyphae if uncertain", "Psoriasis", "Granuloma annulare"], a: 1, r: "Tinea corporis: classic annular (ring-shaped) plaque with raised, erythematous, scaly border and central clearing. Caused by dermatophytes (Trichophyton, Microsporum, Epidermophyton). Diagnosis: clinical or KOH prep (branching septate hyphae). TREATMENT: topical antifungal for 2-4 weeks (terbinafine cream BID, clotrimazole BID, or ketoconazole BID). ORAL antifungal for: extensive disease, immunocompromised, failed topical, tinea capitis (always oral — griseofulvin or terbinafine), or tinea unguium (nail — terbinafine 250 mg daily x 6 weeks fingernails, 12 weeks toenails). Differentiate from: granuloma annulare (no scale), nummular eczema (no central clearing), pityriasis rosea (herald patch then Christmas tree distribution).", s: "Dermatology" },
  { q: "A 55-year-old presents with acute gouty arthritis of the first MTP joint. They have CKD stage 3 (eGFR 45). Which acute treatment is safest?", o: ["Indomethacin 50 mg TID", "Colchicine low-dose regimen (1.2 mg then 0.6 mg one hour later) or systemic corticosteroids (prednisone 0.5 mg/kg x 5-7 days); avoid NSAIDs in CKD", "Allopurinol initiation", "Ketorolac IM"], a: 1, r: "Acute gout with CKD: NSAIDs are CONTRAINDICATED (nephrotoxicity, fluid retention, hyperkalemia). SAFE OPTIONS: 1) Colchicine low-dose regimen (1.2 mg then 0.6 mg one hour later per AGREE trial) if given within 36 hours — reduce dose for CKD (avoid if CrCl <10). 2) Systemic corticosteroids (prednisone 0.5 mg/kg/day x 5-7 days) or intra-articular injection (triamcinolone). 3) IL-1 inhibitor (anakinra) for refractory cases or when other options are contraindicated. Do NOT start/stop/change urate-lowering therapy during acute flare.", s: "Rheumatology" },
  { q: "A 35-year-old presents with recurrent episodes of wheezing only triggered by exercise. Spirometry between episodes is normal. What is the diagnosis and management?", o: ["Chronic asthma requiring daily ICS", "Exercise-induced bronchoconstriction; pre-treat with SABA (albuterol 2 puffs 15 minutes before exercise) or daily low-dose ICS if frequent episodes", "Vocal cord dysfunction", "Cardiac arrhythmia"], a: 1, r: "Exercise-induced bronchoconstriction (EIB): occurs in 40-90% of asthmatics and 10% of general population. Symptoms peak 5-10 minutes after exercise cessation. Diagnosis: exercise challenge test (>=10% drop in FEV1). MANAGEMENT: pre-exercise SABA (albuterol 2 puffs 15-20 minutes before, provides 2-4 hour protection). Alternatives: LTRA (montelukast before exercise), warm-up exercises. If frequent (>2x/week exercise): daily low-dose ICS. Environmental modification: warm/humid air, face mask in cold weather. Rule out: vocal cord dysfunction (inspiratory stridor, flattened inspiratory loop on flow-volume curve), cardiac causes.", s: "Respiratory" },
  { q: "A 62-year-old with type 2 diabetes and CKD stage 3b (eGFR 38) has persistent albuminuria (UACR 350 mg/g) despite maximal ACEi. Which additional medication provides renal protection?", o: ["Second ACEi or ARB", "SGLT2 inhibitor (dapagliflozin or empagliflozin) and finerenone (non-steroidal MRA); both have proven CKD progression reduction independent of diabetes status", "Calcium channel blocker", "Statin"], a: 1, r: "CKD with proteinuria (on maximal RAAS blockade): ADD SGLT2 inhibitor — dapagliflozin (DAPA-CKD: 39% reduction in eGFR decline, approved down to eGFR 20) or empagliflozin (EMPA-KIDNEY). ADD finerenone (FIDELIO-DKD, FIGARO-DKD: non-steroidal MRA, 18% reduction in CKD progression for diabetic CKD). NEVER combine ACEi + ARB (increased AKI/hyperkalemia, no added benefit per ONTARGET). Monitor potassium closely with MRA and RAAS blockade combination. Additional: moderate protein intake (0.8 g/kg/day), sodium restriction (<2g/day), BP <130/80.", s: "Renal & Urologic" },
  { q: "A neonate born at 37 weeks develops jaundice at 18 hours of life. Total bilirubin is 12 mg/dL. What evaluation is needed?", o: ["No evaluation; physiologic jaundice", "Pathologic jaundice (onset <24 hours); workup includes blood type and Coombs test (ABO/Rh incompatibility), CBC with reticulocyte count, peripheral smear, and direct bilirubin to rule out cholestasis", "Only recheck bilirubin at 48 hours", "Start phototherapy without workup"], a: 1, r: "Neonatal jaundice at <24 hours is ALWAYS pathologic. Causes: hemolytic disease (ABO/Rh incompatibility, G6PD deficiency, hereditary spherocytosis), sepsis, TORCH infections. WORKUP: blood type and Coombs test (direct antiglobulin test), CBC with reticulocyte count (elevated reticulocytes suggest hemolysis), peripheral smear (spherocytes, schistocytes), total and direct bilirubin (direct >20% suggests cholestasis: biliary atresia, hepatitis). TREATMENT: plot total bilirubin on Bhutani nomogram. Phototherapy thresholds based on age, gestational age, and risk factors. Exchange transfusion if critical levels. Physiologic jaundice typically appears at 48-72 hours and peaks at days 3-5.", s: "Pediatric" },
  { q: "A 40-year-old woman presents with symmetric joint pain and stiffness in hands and wrists for 4 months, morning stiffness lasting 2 hours, and positive anti-CCP antibodies. What is the treatment approach?", o: ["NSAIDs alone", "Early aggressive treatment with DMARD (methotrexate as first-line) to prevent joint destruction; treat-to-target strategy aiming for remission or low disease activity within 6 months", "Corticosteroids only", "Wait until joint damage is visible"], a: 1, r: "Rheumatoid arthritis treatment: EARLY DMARD initiation is critical (disease modification within window of opportunity). FIRST-LINE: methotrexate 15-25 mg/week (+ folic acid 1 mg daily to reduce side effects). Bridge with low-dose prednisone taper. If inadequate response at 3-6 months: add biologic DMARD (TNF inhibitor: etanercept, adalimumab, infliximab) or targeted synthetic DMARD (JAK inhibitor: tofacitinib, baricitinib, upadacitinib). TREAT-TO-TARGET: assess every 3 months, adjust until remission (DAS28 <2.6) or low disease activity. Monitoring: CBC, LFTs, creatinine every 3 months on methotrexate. Screen for hepatitis B/C and TB before biologics.", s: "Rheumatology" },
  { q: "A 65-year-old presents with chronic cough productive of copious foul-smelling sputum. CT chest shows cylindrical and saccular airway dilation. What is the diagnosis?", o: ["COPD", "Bronchiectasis; treat with airway clearance techniques, mucolytics, inhaled antibiotics for chronic Pseudomonas colonization, and identify underlying cause (CF, immunodeficiency, prior infection)", "Lung abscess", "Lung cancer"], a: 1, r: "Bronchiectasis: permanent airway dilation from chronic inflammation and infection. Causes: post-infectious (TB, pertussis, measles), cystic fibrosis (all patients should be tested), primary ciliary dyskinesia, immunodeficiency (IgG subclass, CVID), allergic bronchopulmonary aspergillosis (ABPA), autoimmune (RA, IBD). CT: cylindrical, varicose, or saccular bronchial dilation, signet ring sign (dilated bronchus larger than adjacent artery). MANAGEMENT: airway clearance (chest physiotherapy, oscillatory PEP devices), mucolytics (hypertonic saline nebulization), antibiotics for exacerbations, long-term macrolide (azithromycin 3x/week) to reduce exacerbations, inhaled tobramycin for chronic Pseudomonas.", s: "Respiratory" },
  { q: "A 50-year-old man presents with decreased libido, erectile dysfunction, fatigue, and loss of body hair. What hormonal evaluation should be performed?", o: ["Only testosterone level", "Morning total testosterone (2 separate occasions), followed by LH/FSH to differentiate primary from secondary hypogonadism; prolactin, iron studies (hemochromatosis), and pituitary MRI if secondary", "PSA only", "Thyroid function only"], a: 1, r: "Male hypogonadism evaluation: TOTAL TESTOSTERONE (8-10 AM, fasting — testosterone has diurnal variation) on TWO separate occasions. If low (<300 ng/dL): determine etiology. PRIMARY (testicular failure): elevated LH/FSH (hypergonadotropic). Causes: Klinefelter syndrome, orchitis, radiation, chemotherapy. SECONDARY (pituitary/hypothalamic): low/normal LH/FSH (hypogonadotropic). Causes: pituitary adenoma, hyperprolactinemia, hemochromatosis, obesity, opioids, glucocorticoids. Additional labs: prolactin, iron studies, pituitary MRI if secondary. TREATMENT: testosterone replacement (gel, injection, patch) if confirmed hypogonadism. Contraindicated in: prostate cancer, polycythemia, severe OSA, desire for fertility (testosterone suppresses spermatogenesis).", s: "Endocrine & Metabolic" },
  { q: "A 15-year-old presents with acute scrotal pain and swelling with a high-riding testicle and absent cremasteric reflex. What is the emergency?", o: ["Epididymitis", "Testicular torsion; surgical emergency requiring detorsion within 6 hours to salvage testis; do not delay for imaging if clinical suspicion is high", "Inguinal hernia", "Hydrocele"], a: 1, r: "Testicular torsion: twisting of spermatic cord causing ischemia. CLASSIC: acute onset severe scrotal pain (often during sleep or activity), nausea/vomiting, high-riding testicle with horizontal lie, absent cremasteric reflex (most sensitive finding). EMERGENCY: testicular salvage rate >90% if detorsion within 6 hours, <10% after 24 hours. If high clinical suspicion: do NOT delay for ultrasound — go directly to OR for surgical exploration and bilateral orchiopexy (fix both sides). If uncertain: emergent color Doppler ultrasound (absent blood flow to affected testicle). Manual detorsion can be attempted: open the book (lateral rotation) while arranging surgery. Differentiate from epididymitis (gradual onset, positive Prehn sign, intact cremasteric reflex) and torsion of appendix testis (blue dot sign).", s: "Renal & Urologic" },
  { q: "A 40-year-old with HIV has a CD4 count of 150. What opportunistic infection prophylaxis is indicated?", o: ["No prophylaxis needed", "TMP-SMX for Pneumocystis jirovecii pneumonia (PCP) when CD4 <200, and azithromycin for Mycobacterium avium complex (MAC) when CD4 <50; continue until immune reconstitution on ART", "Only PCP prophylaxis", "Prophylaxis only if symptomatic"], a: 1, r: "HIV opportunistic infection prophylaxis by CD4 count: CD4 <200: TMP-SMX DS daily for PCP (also covers toxoplasmosis if CD4 <100 and seropositive). Alternative if sulfa allergy: dapsone or atovaquone. CD4 <100: add toxoplasmosis prophylaxis (TMP-SMX covers both). CD4 <50: azithromycin 1200 mg weekly or clarithromycin 500 mg BID for MAC prophylaxis. DISCONTINUE prophylaxis when CD4 >200 for >=3 months on ART (PCP), >100 for >=6 months (toxo), >100 for >=6 months (MAC). ALL HIV patients: ART initiation regardless of CD4 count (START trial). Latent TB testing and treatment.", s: "Infectious Disease" },
  { q: "A 55-year-old presents with chronic constipation, abdominal bloating, and alternating bowel habits. Colonoscopy at age 50 was normal. What is the management?", o: ["Repeat colonoscopy immediately", "Diagnose IBS-C using Rome IV criteria; first-line treatment includes fiber supplementation, PEG-based osmotic laxative, and lifestyle modifications; linaclotide or lubiprostone for refractory cases", "CT abdomen", "Long-term stimulant laxative use"], a: 1, r: "IBS with constipation (IBS-C) management: FIRST-LINE: soluble fiber (psyllium, not insoluble bran which can worsen bloating), adequate hydration, regular exercise. OSMOTIC LAXATIVES: PEG (Miralax) for constipation. PRESCRIPTION if refractory: linaclotide (guanylate cyclase C agonist, improves pain and constipation), lubiprostone (chloride channel activator), plecanatide. Antispasmodics for pain (dicyclomine, hyoscyamine). Low FODMAP diet (evidence-based for IBS symptoms). CBT and gut-directed hypnotherapy have good evidence. AVOID chronic stimulant laxatives. Red flags requiring workup: age >50 without recent colonoscopy, rectal bleeding, weight loss, family history CRC, anemia, nocturnal symptoms.", s: "Gastrointestinal" },
  { q: "A 30-year-old with type 1 diabetes and microalbuminuria (UACR 120 mg/g) has BP of 135/85. What is the treatment?", o: ["No treatment until UACR >300", "Initiate ACE inhibitor (lisinopril or ramipril) to reduce microalbuminuria and slow progression to diabetic nephropathy; target BP <130/80", "Start calcium channel blocker", "Dietary sodium restriction only"], a: 1, r: "Diabetic kidney disease prevention: ACEi or ARB is indicated for ALL patients with diabetes and albuminuria (UACR >30 mg/g), regardless of blood pressure — they reduce intraglomerular pressure and proteinuria independent of BP effect. For T1D: ACEi preferred (IDNT and RENAAL trials for T2D; Captopril Collaborative study for T1D). Target BP <130/80 (KDIGO). Additional: optimize A1c (<7%), SGLT2 inhibitor if T2D (or T1D with specialist guidance), statin for cardiovascular risk reduction, sodium restriction, moderate protein intake. Monitor potassium and creatinine 1-2 weeks after ACEi initiation (up to 30% Cr rise acceptable).", s: "Endocrine & Metabolic" },
  { q: "A 60-year-old presents with progressive bilateral hearing loss, tinnitus, and difficulty understanding speech especially in noisy environments. Weber test lateralizes to the right (better-hearing ear). What is the diagnosis?", o: ["Conductive hearing loss", "Age-related sensorineural hearing loss (presbycusis); bilateral, symmetric, high-frequency loss. Weber lateralizes to better-hearing ear in SNHL. Refer for formal audiometry and hearing aid evaluation", "Meniere disease", "Acoustic neuroma"], a: 1, r: "Presbycusis: most common cause of hearing loss in adults, bilateral symmetric high-frequency SNHL. Pathology: cochlear hair cell loss (outer hair cells first, then inner). Weber: lateralizes to BETTER ear (in SNHL, sound is louder in unaffected ear). Rinne: AC > BC bilaterally (normal Rinne, but overall diminished). EVALUATION: formal audiometry (shows bilateral high-frequency sloping loss). MANAGEMENT: hearing aids (most effective intervention, improve quality of life and may slow cognitive decline), assistive listening devices, communication strategies. Cochlear implant for severe bilateral SNHL. Association with cognitive decline: Lancet Commission identified hearing loss as the largest modifiable risk factor for dementia.", s: "ENT" },
  { q: "A 45-year-old with persistent atrial fibrillation has CHA2DS2-VASc score of 3 (HTN, DM, female). What anticoagulation is recommended?", o: ["Aspirin 325 mg daily", "Direct oral anticoagulant (apixaban, rivaroxaban, dabigatran, or edoxaban) preferred over warfarin for non-valvular AF; apixaban has the best safety profile for bleeding risk", "Clopidogrel only", "No anticoagulation needed"], a: 1, r: "AF anticoagulation: CHA2DS2-VASc >=2 (men) or >=3 (women): anticoagulation recommended. DOAC PREFERRED over warfarin for non-valvular AF (except mechanical valve or moderate-severe mitral stenosis). DOAC comparison: apixaban (ARISTOTLE: lowest major bleeding, no dose adjustment for renal function except extreme), rivaroxaban (once daily, take with food), dabigatran (BID, has reversal agent idarucizumab), edoxaban (once daily after 5 days of parenteral anticoagulation). DOSE REDUCTION criteria vary by drug: apixaban reduced dose if 2 of 3 (age >=80, weight <=60 kg, Cr >=1.5). HAS-BLED score assesses bleeding risk but should not prevent anticoagulation if indicated.", s: "Cardiovascular" },
  { q: "A patient with chronic hepatitis B has HBV DNA >20,000 IU/mL, elevated ALT, and liver biopsy showing moderate fibrosis. What is the treatment?", o: ["Monitor without treatment", "Initiate antiviral therapy with entecavir or tenofovir (TDF or TAF); these are first-line nucleos(t)ide analogues with high barrier to resistance", "Interferon injection only", "Liver transplant evaluation"], a: 1, r: "Chronic HBV treatment indications: HBV DNA >2000 IU/mL + elevated ALT + significant fibrosis/inflammation. FIRST-LINE: entecavir 0.5 mg daily or tenofovir (TDF 300 mg or TAF 25 mg daily) — both have high efficacy and high barrier to resistance. TAF preferred over TDF for patients with renal impairment or osteoporosis risk. Pegylated interferon-alpha: alternative for finite duration therapy (48 weeks), but contraindicated in decompensated cirrhosis. TREATMENT GOALS: HBV DNA suppression, ALT normalization, HBeAg seroconversion, and ideally HBsAg loss (functional cure, rare with NAs). Duration: often lifelong for HBeAg-negative disease. Monitor: HBV DNA and ALT every 3-6 months, HCC surveillance (ultrasound every 6 months if cirrhotic or high-risk).", s: "Gastrointestinal" },
  { q: "A 3-year-old presents with limp and refusal to bear weight. Temperature is 39.2C. WBC is 18,000. ESR is 55 mm/hr. What must be ruled out emergently?", o: ["Growing pains", "Septic arthritis; perform urgent joint aspiration (synovial fluid WBC >50,000 with >75% PMNs is diagnostic); start IV antibiotics immediately after aspiration", "Transient synovitis", "Legg-Calve-Perthes disease"], a: 1, r: "Septic arthritis in children: EMERGENCY (joint destruction occurs rapidly). Differentiate from transient synovitis using Kocher criteria: fever, non-weight-bearing, ESR >40, WBC >12,000. >=3 criteria: 93% probability of septic arthritis. DIAGNOSIS: joint aspiration is essential (WBC >50,000, >75% PMNs, positive culture). Most common organism: S. aureus (all ages), Kingella kingae (6 months to 4 years). TREATMENT: emergent joint aspiration/irrigation (orthopedic consultation), IV antibiotics (nafcillin/oxacillin + ceftriaxone empirically, or vancomycin if MRSA suspected). Duration: typically 3-4 weeks (IV then transition to oral). Transient synovitis: afebrile/low-grade, less elevated labs, Kocher criteria <2.", s: "Pediatric" },
  { q: "A 70-year-old woman on hormone replacement therapy for 8 years asks about continuing. What does the evidence suggest?", o: ["Continue indefinitely", "Reassess periodically; WHI data showed increased risks of breast cancer, CVD, stroke, and VTE with long-term combined HRT; consider lowest dose for shortest duration to manage persistent vasomotor symptoms", "Stop immediately without taper", "Switch to higher dose"], a: 1, r: "Long-term HRT reassessment: WHI (Women's Health Initiative) findings for combined estrogen+progestin: increased risks of breast cancer (HR 1.26), coronary events, stroke, VTE. Estrogen alone (post-hysterectomy): no increased breast cancer risk, decreased hip fracture. CURRENT RECOMMENDATIONS: reassess annually, use lowest effective dose for shortest duration. STOPPING: if vasomotor symptoms resolved, gradually taper (abrupt cessation may cause rebound symptoms). CONTINUING may be appropriate if: persistent severe vasomotor symptoms, individualized risk-benefit analysis favorable, bone protection needed without alternatives. Timing hypothesis: HRT initiated within 10 years of menopause or before age 60 has more favorable cardiovascular risk profile.", s: "Women's Health" },
  { q: "A 25-year-old presents with acute low back pain after lifting. No red flag symptoms. Neurological exam is normal. What is the evidence-based management?", o: ["Immediate MRI", "Reassurance, activity modification (avoid bed rest), NSAIDs, non-pharmacologic therapies (heat, spinal manipulation), and follow-up in 4-6 weeks if not improving", "Opioid prescription", "Surgical referral"], a: 1, r: "Acute low back pain without red flags: ACP guidelines. IMAGING NOT indicated in first 6 weeks unless red flags present: RED FLAGS (cancer: history, weight loss, age >50; cauda equina: urinary retention, saddle anesthesia, progressive weakness; fracture: trauma, osteoporosis, steroid use; infection: fever, IVDU, immunosuppression). TREATMENT: stay active (bed rest worsens outcomes), NSAIDs (first-line pharmacologic), non-pharmacologic (superficial heat, massage, spinal manipulation, acupuncture). Muscle relaxants short-term if needed. AVOID opioids if possible (ACP weak recommendation for severe pain when other options fail). Most acute LBP resolves in 4-6 weeks. If not improving: consider imaging and PT referral.", s: "Musculoskeletal" },
  { q: "A 55-year-old patient on warfarin for atrial fibrillation develops an INR of 3.8 with no bleeding. The patient also just started amoxicillin-clavulanate for sinusitis. What is the likely cause of the elevated INR?", o: ["Dietary change", "Amoxicillin-clavulanate can potentiate warfarin by disrupting vitamin K-producing intestinal flora and possible CYP450 interaction; hold warfarin dose, recheck INR in 2-3 days, and resume at reduced dose", "Random variation", "Warfarin resistance"], a: 1, r: "Warfarin drug interactions with antibiotics: many antibiotics potentiate warfarin effect through: 1) disruption of vitamin K-producing gut flora (amoxicillin, fluoroquinolones, TMP-SMX), 2) CYP450 inhibition (metronidazole, fluconazole, TMP-SMX inhibit CYP2C9). TMP-SMX is the most potent antibiotic potentiator. Management of INR 3.5-4.5 without bleeding: hold 1-2 warfarin doses, recheck INR in 2-3 days, resume at reduced dose. ALWAYS consider drug interactions when prescribing to patients on warfarin. Alternative approach: increase INR monitoring frequency (every 1-2 weeks) when starting or stopping any interacting medication.", s: "Hematology" },
{ q: "The classic ruptured AAA triad includes sudden abdominal/back pain, hypotension, and pulsatile abdominal mass. In what percentage of cases is the full triad present?", o: ["<50%", "75%", "90%", "100%"], a: 0, r: "The classic triad is present in fewer than 50% of ruptured AAA cases. The clinician must maintain high suspicion in any elderly male smoker with sudden abdominal or back pain and hemodynamic instability, even without a palpable pulsatile mass.", s: "Cardiovascular" },
  { q: "Which law of physics explains why rupture risk increases exponentially with AAA diameter?", o: ["Boyle's law", "Law of Laplace", "Poiseuille's law", "Bernoulli's principle"], a: 1, r: "The Law of Laplace states wall tension = (pressure × radius) / (2 × wall thickness). As the aneurysm enlarges, wall tension increases proportionally to radius. Combined with wall thinning, this exponentially increases rupture risk at larger diameters.", s: "Cardiovascular" },
  { q: "A 70-year-old man with a known 5.0 cm AAA develops sudden severe back pain and BP drops to 90/60. What is the immediate priority?", o: ["MRI of the lumbar spine", "Schedule outpatient CT in 1 week", "Emergent vascular surgery consultation and permissive hypotension (SBP 70-90)", "NSAIDs and discharge home"], a: 2, r: "This presentation is concerning for ruptured or leaking AAA. Immediate vascular surgery consultation is critical. Permissive hypotension (SBP 70-90 mmHg) prevents clot disruption at the rupture site while maintaining cerebral perfusion. Ruptured AAA carries 80-90% mortality.", s: "Cardiovascular" },
  { q: "What is the mortality rate for ruptured AAA including prehospital deaths?", o: ["20-30%", "40-50%", "60-70%", "80-90%"], a: 3, r: "Ruptured AAA carries 80-90% overall mortality, with 50% of patients dying before reaching the hospital. This is why screening and elective repair are critical — elective EVAR has 1-2% mortality vs 80-90% for ruptured repair.", s: "Cardiovascular" },
  { q: "After EVAR repair of an AAA, what lifelong surveillance is required?", o: ["No follow-up needed", "Annual chest X-ray", "CT angiography at 1, 6, 12 months then annually to monitor for endoleak", "Abdominal X-ray every 5 years"], a: 2, r: "EVAR requires lifelong CT angiography surveillance for endoleaks (persistent blood flow into the aneurysm sac around or through the stent graft). Endoleaks can lead to continued aneurysm sac pressurization and delayed rupture. This is a key counseling point.", s: "Cardiovascular" },
  { q: "What surveillance interval is recommended for a 4.2 cm AAA?", o: ["No surveillance needed", "Every 3 years", "Every 12 months", "Every 6 months"], a: 2, r: "AAA surveillance intervals by size: 3.0-3.9 cm every 3 years, 4.0-4.9 cm every 12 months, 5.0-5.4 cm every 6 months. Repair is considered at ≥5.5 cm (men) or ≥5.0 cm (women), rapid expansion >1 cm/year, or symptoms.", s: "Cardiovascular" },
  { q: "Which first-degree relatives of AAA patients should be screened?", o: ["No screening recommended for relatives", "Siblings — who have an 18% prevalence of AAA", "Only female relatives", "Only relatives over age 80"], a: 1, r: "Siblings of AAA patients have approximately 18% prevalence of AAA (vs 5-10% in the general male population >65). First-degree relatives, especially brothers and sons, should be screened with abdominal ultrasound at age 65 or earlier if symptomatic.", s: "Cardiovascular" },
  { q: "A patient with thalassemia trait has microcytic anemia. Their Mentzer index (MCV/RBC) is 11. What does this suggest?", o: ["Iron deficiency anemia", "Thalassemia trait", "Macrocytic anemia", "Normal hemoglobin"], a: 1, r: "Mentzer index <13 suggests thalassemia trait (many small red cells with elevated RBC count), while >13 suggests iron deficiency (fewer cells overall). This patient's value of 11 favors thalassemia. Must be confirmed with iron studies and hemoglobin electrophoresis.", s: "Hematology" },
  { q: "A 28-year-old of Greek descent has mild anemia (Hb 11.5), MCV 66, RBC 6.2 million, and hemoglobin electrophoresis showing HbA2 5.8%. What is the diagnosis?", o: ["Iron deficiency anemia", "Beta-thalassemia trait", "Alpha-thalassemia trait", "Sickle cell trait"], a: 1, r: "Mild microcytic anemia with elevated RBC count, normal/elevated iron stores, and elevated HbA2 (>3.5%, typically 4-8%) on hemoglobin electrophoresis is diagnostic of beta-thalassemia trait. No treatment needed but genetic counseling is essential.", s: "Hematology" },
  { q: "Why should iron supplementation be AVOIDED in thalassemia trait?", o: ["It causes hemolysis", "Patients already have normal or elevated iron stores, and supplementation causes iatrogenic iron overload", "It interferes with hemoglobin electrophoresis", "It worsens anemia"], a: 1, r: "Thalassemia trait patients have normal or elevated iron stores. Misdiagnosing thalassemia trait as iron deficiency and prescribing iron causes iatrogenic iron overload with potential organ damage. Always confirm iron studies before treating any microcytic anemia with iron.", s: "Hematology" },
  { q: "What is the most common genetic risk factor for Parkinson disease?", o: ["LRRK2 mutation", "SNCA duplication", "GBA (glucocerebrosidase) mutation", "PARK2/Parkin mutation"], a: 2, r: "GBA (glucocerebrosidase) mutations are the most common genetic risk factor for PD, found in 5-10% of PD patients. GBA encodes a lysosomal enzyme; its dysfunction impairs alpha-synuclein degradation, promoting accumulation. LRRK2 is the most common cause of autosomal dominant PD.", s: "Neurological" },
  { q: "In beta-thalassemia major, what causes the characteristic 'chipmunk facies' and frontal bossing?", o: ["Chronic steroid use", "Bone marrow hyperplasia from compensatory erythropoiesis expanding the medullary space", "Iron deposition in facial bones", "Chronic malnutrition"], a: 1, r: "In beta-thalassemia major, ineffective erythropoiesis triggers massive compensatory marrow expansion, which causes skeletal changes: frontal bossing, maxillary hyperplasia (chipmunk facies), and the classic 'hair-on-end' or 'crew cut' appearance on skull X-ray from diploe widening.", s: "Hematology" },
  { q: "What is the leading cause of death in transfusion-dependent thalassemia?", o: ["Infection", "Renal failure", "Cardiac iron overload (cardiomyopathy/heart failure)", "Hepatocellular carcinoma"], a: 2, r: "Cardiac iron overload is the leading cause of death in transfusion-dependent thalassemia. Each unit of RBCs contains ~250 mg iron, and the body has no active iron excretion mechanism. Iron deposits in the myocardium cause dilated cardiomyopathy, arrhythmias, and heart failure.", s: "Hematology" },
  { q: "Cardiac MRI T2* of 12 ms in a thalassemia patient indicates:", o: ["Normal cardiac iron", "Mild cardiac iron loading", "Moderate cardiac iron loading requiring intensified chelation", "No clinical significance"], a: 2, r: "Cardiac MRI T2* <20 ms indicates cardiac iron loading (normal >20 ms). T2* 10-20 ms represents moderate loading; <10 ms indicates severe loading with high risk of heart failure. Intensive chelation with deferiprone ± deferoxamine is recommended for T2* <20 ms.", s: "Hematology" },
  { q: "Which iron chelator is administered as a daily oral medication and is first-line for transfusional iron overload?", o: ["Deferoxamine", "Deferasirox (Jadenu)", "Deferiprone", "EDTA"], a: 1, r: "Deferasirox (Jadenu film-coated tablets) is the first-line oral iron chelator, given once daily at 14-28 mg/kg/day. It has better adherence than deferoxamine (which requires 8-12 hour SC infusion) and better GI tolerability than the older dispersible formulation (Exjade).", s: "Pharmacology" },
  { q: "Alpha-thalassemia with all four alpha-globin genes deleted (--/--) produces which incompatible-with-life condition?", o: ["HbH disease", "Hydrops fetalis (Hb Bart's)", "Sickle cell crisis", "Aplastic anemia"], a: 1, r: "Deletion of all four alpha-globin genes produces hydrops fetalis. Without alpha chains, gamma chains form tetramers (Hb Bart's, γ4) which have extremely high oxygen affinity and cannot release oxygen to tissues. The fetus develops severe anemia, edema, and dies in utero or shortly after birth.", s: "Hematology" },
  { q: "In which ethnic population is the cis form of alpha-thalassemia (--/αα) most common, carrying the highest risk for hydrops fetalis in offspring?", o: ["African American", "Southeast Asian", "Northern European", "Hispanic"], a: 1, r: "Southeast Asian populations commonly carry the cis deletion (--/αα, both deletions on one chromosome 16). If both parents carry cis deletions, there is a 25% chance of offspring with four-gene deletion (hydrops fetalis). African Americans typically carry trans deletions (-α/-α), with very low hydrops risk.", s: "Hematology" },
  { q: "What is the only curative treatment for beta-thalassemia major?", o: ["Iron chelation therapy", "Chronic transfusion program", "Allogeneic hematopoietic stem cell transplant", "Splenectomy"], a: 2, r: "Allogeneic HSCT (bone marrow transplant) is the only curative option for beta-thalassemia major. Best outcomes occur in young children with HLA-matched sibling donors (>90% cure rate). Gene therapy (Zynteglo) is a newer FDA-approved curative option using autologous gene-modified stem cells.", s: "Hematology" },
  { q: "Hemoglobin electrophoresis is often NORMAL in which thalassemia diagnosis?", o: ["Beta-thalassemia trait", "Beta-thalassemia major", "Alpha-thalassemia trait (1-2 gene deletions)", "HbH disease"], a: 2, r: "In alpha-thalassemia trait (1-2 gene deletions), HbA2 and HbF are not elevated because the defect affects alpha chains (not beta). Hemoglobin electrophoresis appears normal. Definitive diagnosis requires genetic testing (PCR-based alpha-globin gene analysis).", s: "Hematology" },
  { q: "A patient with RA has been on methotrexate 15 mg weekly for 8 weeks. Lab monitoring shows ALT 3x upper limit of normal. What should the NP do?", o: ["Continue MTX and recheck in 6 months", "Hold methotrexate until transaminases normalize, then restart at lower dose with closer monitoring", "Increase MTX dose", "Add adalimumab immediately"], a: 1, r: "MTX should be held if ALT/AST exceeds 2x ULN. Causes include MTX hepatotoxicity, NAFLD, or alcohol use. After transaminases normalize, MTX can be restarted at a lower dose with closer monitoring (every 2-4 weeks). If recurrent elevation, consider alternative DMARD.", s: "Pharmacology" },
  { q: "A nurse practitioner is counseling a patient starting methotrexate for RA. Which statement about dosing is MOST important?", o: ["Take it daily with food", "Methotrexate is dosed WEEKLY — daily dosing is a fatal medication error causing pancytopenia", "Take it twice daily", "Take it every other day"], a: 1, r: "Methotrexate for RA is dosed ONCE WEEKLY, not daily. Inadvertent daily dosing has caused fatal pancytopenia, severe mucositis, and multiorgan failure. The NP must clearly communicate 'once weekly on the same day each week' and verify patient understanding at every visit.", s: "Pharmacology" },
  { q: "Anti-CCP antibodies (ACPA) in rheumatoid arthritis are significant because they:", o: ["Are found in all autoimmune diseases equally", "Have 95-99% specificity for RA and predict erosive disease course", "Are only positive in late-stage RA", "Indicate viral arthritis"], a: 1, r: "Anti-CCP antibodies are 95-99% specific for RA (much more specific than RF at 80%) and predict an erosive, more aggressive disease course. They can be detected years before clinical disease onset (preclinical RA). A positive anti-CCP essentially confirms RA in the setting of inflammatory arthritis.", s: "Assessment" },
  { q: "What is the initial DMARD treatment recommended for newly diagnosed rheumatoid arthritis?", o: ["Adalimumab (Humira)", "Prednisone 20 mg daily indefinitely", "Methotrexate 10-15 mg weekly with folic acid 1 mg daily", "Ibuprofen 800 mg TID"], a: 2, r: "Methotrexate is the anchor DMARD and should be initiated within 3 months of RA diagnosis per treat-to-target guidelines. Start at 10-15 mg weekly, titrate to 20-25 mg. Co-prescribe folic acid 1 mg daily to reduce side effects. Biologics are reserved for inadequate response to conventional DMARDs.", s: "Pharmacology" },
  { q: "Before starting a biologic DMARD (e.g., adalimumab), which screening tests are mandatory?", o: ["Only CBC", "TB screening (QuantiFERON Gold) and hepatitis B/C serologies", "Only hepatic function tests", "No screening is needed"], a: 1, r: "Before biologic DMARDs, patients must be screened for latent TB (QuantiFERON Gold or PPD — TNF inhibitors reactivate TB) and hepatitis B/C (rituximab reactivates HBV). Latent TB must be treated for at least 1 month before biologic initiation. Also obtain baseline CBC, CMP, and chest X-ray.", s: "Assessment" },
  { q: "What is the mechanism of action of adalimumab (Humira)?", o: ["Inhibits IL-6 receptor", "Depletes CD20+ B cells", "Binds and neutralizes TNF-alpha, blocking inflammatory signaling in the synovium", "Blocks T-cell co-stimulation"], a: 2, r: "Adalimumab is a fully human monoclonal antibody that binds both soluble and transmembrane TNF-alpha, preventing its interaction with TNF receptors (p55/p75). This reduces inflammatory cell infiltration, MMP production, and osteoclast activation in the RA synovium.", s: "Pharmacology" },
  { q: "A patient with RA develops dry cough and progressive dyspnea on MTX. CXR shows bilateral ground-glass opacities. What is the priority diagnosis?", o: ["Community-acquired pneumonia", "Methotrexate-induced pneumonitis — hold MTX immediately", "Rheumatoid lung nodules", "Pulmonary embolism"], a: 1, r: "MTX-induced pneumonitis is a hypersensitivity reaction (not dose-dependent) presenting with acute dry cough, dyspnea, and bilateral infiltrates. It is a medical emergency: stop MTX immediately, rule out infection (especially PCP in immunosuppressed), start systemic corticosteroids. Never rechallenge with MTX.", s: "Pharmacology" },
  { q: "Which RA deformity involves hyperextension of the PIP joint and flexion of the DIP joint?", o: ["Boutonnière deformity", "Swan-neck deformity", "Ulnar deviation", "Z-thumb deformity"], a: 1, r: "Swan-neck deformity: hyperextension PIP + flexion DIP. Boutonnière deformity: flexion PIP + hyperextension DIP. These are late findings of untreated RA resulting from pannus erosion of tendons and joint capsules. Early DMARD therapy prevents these deformities.", s: "Assessment" },
  { q: "C1-C2 (atlantoaxial) subluxation in RA requires evaluation before what clinical scenario?", o: ["MRI of the knee", "Any surgical procedure requiring intubation", "Routine blood draws", "Annual physical exam"], a: 1, r: "Atlantoaxial subluxation from pannus erosion of the transverse ligament occurs in up to 25% of RA patients. Flexion-extension lateral cervical spine X-rays must be obtained before intubation or surgery to assess for spinal cord compression risk during neck extension.", s: "Assessment" },
  { q: "The treat-to-target strategy in RA means:", o: ["Treat only when symptoms are severe", "Measure disease activity at every visit and escalate therapy every 3-6 months until remission or low disease activity is achieved", "Use biologics as first-line in all patients", "Taper all medications after 6 months"], a: 1, r: "Treat-to-target (T2T) requires measuring disease activity using validated tools (DAS28, CDAI, SDAI) at every visit. If the target (remission or low disease activity) is not met, therapy is escalated every 3-6 months. Persistent moderate/high disease activity should not be accepted.", s: "Assessment" },
  { q: "Felty syndrome is a triad of:", o: ["RA + hepatomegaly + thrombocytopenia", "RA + splenomegaly + neutropenia", "RA + lymphadenopathy + anemia", "RA + nephritis + proteinuria"], a: 1, r: "Felty syndrome is a triad of rheumatoid arthritis, splenomegaly, and neutropenia. It occurs in long-standing, seropositive RA and increases infection risk due to neutropenia. Large granular lymphocyte (LGL) leukemia should be excluded. Treatment focuses on aggressive RA management.", s: "Assessment" },
  { q: "Which antibiotic class carries FDA boxed warnings for tendinopathy, peripheral neuropathy, CNS effects, aortic dissection, and hypoglycemia?", o: ["Penicillins", "Macrolides", "Fluoroquinolones", "Tetracyclines"], a: 2, r: "Fluoroquinolones (ciprofloxacin, levofloxacin, moxifloxacin) carry boxed warnings for disabling and potentially irreversible tendinopathy/rupture, peripheral neuropathy, CNS effects, aortic dissection/aneurysm, and hypoglycemia. They should be reserved for infections without safer alternatives.", s: "Pharmacology" },
  { q: "A hospitalized patient on broad-spectrum antibiotics for 10 days develops watery diarrhea and WBC 25,000. What is the most likely diagnosis?", o: ["Viral gastroenteritis", "Clostridioides difficile infection (CDI)", "Food poisoning", "Inflammatory bowel disease flare"], a: 1, r: "C. difficile infection is the most common healthcare-associated infection in the US. Risk factors include broad-spectrum antibiotics (especially fluoroquinolones, clindamycin, cephalosporins), hospitalization, and age >65. Diagnosis: stool NAAT (PCR) or two-step testing (GDH + toxin EIA).", s: "Infectious Disease" },
  { q: "What is the preferred first-line treatment for initial C. difficile infection per IDSA 2021 guidelines?", o: ["Metronidazole 500 mg PO TID", "Fidaxomicin 200 mg PO BID for 10 days", "IV vancomycin", "Ciprofloxacin"], a: 1, r: "IDSA 2021 guidelines prefer fidaxomicin over oral vancomycin for initial CDI due to significantly lower recurrence rates (13% vs 27%). Metronidazole is no longer recommended for initial episodes due to inferior outcomes. IV vancomycin does not reach the colonic lumen.", s: "Pharmacology" },
  { q: "Why is oral vancomycin used for C. difficile but NOT for MRSA bacteremia?", o: ["Different formulations exist", "Oral vancomycin is NOT absorbed systemically — it acts locally in the GI tract for CDI; IV vancomycin is needed for systemic MRSA infections", "Oral vancomycin treats both equally", "MRSA is resistant to vancomycin"], a: 1, r: "Oral vancomycin has negligible systemic absorption — it remains in the GI lumen at high concentrations, ideal for treating CDI locally. For systemic infections (MRSA bacteremia, endocarditis), IV vancomycin is required to achieve adequate serum and tissue levels.", s: "Pharmacology" },
  { q: "Red Man Syndrome from vancomycin infusion is caused by:", o: ["IgE-mediated anaphylaxis", "Histamine release from rapid infusion — NOT a true allergy", "Complement activation", "Drug-induced lupus"], a: 1, r: "Red Man Syndrome is a non-immune histamine-mediated reaction from rapid vancomycin infusion, causing flushing, erythema, and pruritus of the upper body. Management: slow the infusion rate and premedicate with diphenhydramine. It is NOT anaphylaxis and does NOT contraindicate future vancomycin use.", s: "Pharmacology" },
  { q: "ESBL-producing E. coli appears susceptible to ceftriaxone on sensitivity testing. What antibiotic should be used for a serious infection?", o: ["Ceftriaxone based on susceptibility", "Meropenem — carbapenems are the drug of choice regardless of cephalosporin susceptibility", "Ciprofloxacin", "Amoxicillin-clavulanate"], a: 1, r: "Despite in vitro susceptibility, ESBL-producing organisms have high clinical failure rates with cephalosporins and beta-lactam/beta-lactamase inhibitors (inoculum effect). Carbapenems are the drugs of choice for serious ESBL infections. This is a critical antimicrobial stewardship concept.", s: "Pharmacology" },
  { q: "The three core principles of antibiotic stewardship are:", o: ["Prescribe the broadest spectrum, longest duration, always IV route", "Obtain cultures before antibiotics, de-escalate within 48-72 hours, use shortest effective duration", "Rotate antibiotics monthly, combine two antibiotics always, treat empirically forever", "Use only one class of antibiotics, avoid cultures, treat for minimum 21 days"], a: 1, r: "Core stewardship principles: (1) Obtain cultures before antibiotics, (2) De-escalate within 48-72 hours based on culture/sensitivity results, (3) Use the shortest effective duration. These reduce resistance emergence, C. difficile risk, and adverse drug events.", s: "Infectious Disease" },
  { q: "Procalcitonin levels can guide antibiotic therapy. At what level should antibiotics generally be discontinued?", o: [">2.0 ng/mL", ">0.5 ng/mL", "<0.25 ng/mL or >80% drop from peak", "<0.01 ng/mL"], a: 2, r: "Procalcitonin-guided therapy: antibiotics may be safely discontinued when PCT drops <0.25 ng/mL or decreases >80% from peak value. This strategy reduces antibiotic duration without increasing adverse outcomes, particularly in respiratory infections and sepsis.", s: "Infectious Disease" },
  { q: "What is AUC/MIC-guided dosing of vancomycin, and why is it preferred over trough-based dosing?", o: ["It is outdated", "AUC/MIC target 400-600 is preferred per 2020 guidelines because it achieves therapeutic efficacy with less nephrotoxicity than trough-based dosing", "Trough-based dosing is always safer", "AUC/MIC applies only to oral vancomycin"], a: 1, r: "The 2020 ASHP/IDSA guidelines shifted from trough-based vancomycin monitoring (target 15-20 mcg/mL) to AUC/MIC-guided dosing (target AUC/MIC 400-600). AUC-guided dosing achieves equivalent efficacy with significantly less nephrotoxicity.", s: "Pharmacology" },
  { q: "Which antibiotic should NOT be used for pneumonia caused by MRSA?", o: ["Vancomycin IV", "Linezolid", "Daptomycin", "TMP-SMX"], a: 2, r: "Daptomycin is inactivated by pulmonary surfactant and must NEVER be used for pneumonia. For MRSA pneumonia, use vancomycin IV or linezolid. Daptomycin is effective for MRSA bacteremia, endocarditis, and skin/soft tissue infections.", s: "Pharmacology" },
  { q: "Live vaccines are contraindicated in all of the following EXCEPT:", o: ["Pregnancy", "Patient on ≥20 mg prednisone daily for ≥14 days", "HIV patient with CD4 count of 350", "Patient receiving chemotherapy"], a: 2, r: "Live vaccines (MMR, varicella, LAIV, rotavirus, yellow fever) are contraindicated in pregnancy, severe immunodeficiency, active chemotherapy, and high-dose steroids (≥20 mg prednisone x ≥14 days). HIV patients with CD4 ≥200 CAN receive most live vaccines. CD4 350 is above the threshold.", s: "Preventive Care" },
  { q: "Shingrix (recombinant zoster vaccine) differs from the old Zostavax in that:", o: ["Shingrix is a live vaccine", "Shingrix is non-live (recombinant) with >90% efficacy and CAN be given to immunocompromised patients", "Shingrix has lower efficacy", "Shingrix requires only one dose"], a: 1, r: "Shingrix is recombinant (non-live) with 97% efficacy in adults 50-69 and 91% in ≥70 years old. Unlike Zostavax (live, <50% effective, contraindicated in immunosuppressed), Shingrix CAN be safely given to immunocompromised patients. Two doses IM, 2-6 months apart.", s: "Preventive Care" },
  { q: "When should Tdap be given during pregnancy?", o: ["First trimester only", "27-36 weeks gestation during EACH pregnancy", "Only once in a lifetime", "Only postpartum"], a: 1, r: "ACIP recommends Tdap during EACH pregnancy at 27-36 weeks to maximize transplacental transfer of pertussis antibodies to the neonate. This protects infants during the vulnerable period before their own DTaP series begins at 2 months. Pertussis is life-threatening in neonates.", s: "Preventive Care" },
  { q: "The simplified 2023 ACIP pneumococcal vaccine recommendation for adults ≥65 who have never been vaccinated is:", o: ["PPSV23 alone", "PCV13 followed by PPSV23", "PCV20 single dose", "No pneumococcal vaccine needed"], a: 2, r: "Simplified 2023 ACIP guidelines: PCV20 (Prevnar 20) single dose for pneumococcal-naive adults ≥65 and high-risk adults 19-64. This replaces the complex PCV13 → PPSV23 regimen. PCV15 followed by PPSV23 (≥1 year later) is an acceptable alternative.", s: "Preventive Care" },
  { q: "A healthy 24-year-old asks about HPV vaccination. Per ACIP, what is the recommendation?", o: ["HPV vaccine is not recommended after age 18", "HPV vaccine is routinely recommended through age 26; shared clinical decision for ages 27-45", "HPV vaccine is only for females", "Only 1 dose is needed after age 15"], a: 1, r: "HPV vaccination is routinely recommended through age 26 for all genders. For ages 27-45, shared clinical decision-making is recommended (catch-up vaccination for those who would benefit). Standard series: 2 doses if started before age 15, 3 doses if started at age 15+.", s: "Preventive Care" },
  { q: "The ACIP 2022 universal adult hepatitis B vaccine recommendation applies to which age group?", o: ["All adults regardless of age", "All unvaccinated adults aged 19-59; shared decision for ≥60", "Only healthcare workers", "Only adults with chronic liver disease"], a: 1, r: "ACIP 2022 simplified HBV vaccination: universal recommendation for all unvaccinated adults 19-59 WITHOUT risk-factor screening. For adults ≥60, it is a shared clinical decision. This eliminates the previous requirement to assess risk factors before recommending HBV vaccine.", s: "Preventive Care" },
  { q: "Which pneumococcal vaccine technology enables immunological memory by converting T-independent to T-dependent immune response?", o: ["Polysaccharide vaccine (PPSV23)", "Conjugate vaccine (PCV) — polysaccharide conjugated to carrier protein", "Live attenuated vaccine", "mRNA vaccine"], a: 1, r: "Conjugate vaccines link polysaccharide antigens to a carrier protein (CRM197 diphtheria toxoid mutant in PCV), converting the T-independent B-cell response to a T-dependent response. This produces immunological memory, higher-affinity antibodies, and mucosal immunity — advantages over PPSV23.", s: "Preventive Care" }
];
